import socket
import threading
import json
import math

class GameServer:
    def __init__(self, host='127.0.0.1', port=12345):
        self.server = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server.bind((host, port))
        self.server.listen()
        self.clients = []
        self.player_positions = {}
        self.lock = threading.Lock()

    def broadcast(self, message):
        with self.lock:
            for client in self.clients:
                try:
                    client.send(message)
                except Exception as e:
                    print(f"Error sending message: {e}")

    def handle_client(self, client_socket):
        while True:
            try:
                data = client_socket.recv(1024)
                if not data:
                    break
                player_data = json.loads(data.decode('utf-8'))
                self.update_player_position(player_data)
                self.broadcast_game_state()
            except Exception as e:
                print(f"Error handling client: {e}")
                break
        self.remove_client(client_socket)

    def update_player_position(self, player_data):
        player_id = player_data['id']
        position = player_data['position']
        with self.lock:
            self.player_positions[player_id] = position

    def broadcast_game_state(self):
        with self.lock:
            message = json.dumps(self.player_positions).encode('utf-8')
            self.broadcast(message)

    def remove_client(self, client_socket):
        with self.lock:
            self.clients.remove(client_socket)
        client_socket.close()

    def start(self):
        print("Server started...")
        while True:
            client_socket, addr = self.server.accept()
            print(f"Connection from {addr}")
            self.clients.append(client_socket)
            threading.Thread(target=self.handle_client, args=(client_socket,)).start()

if __name__ == "__main__":
    server = GameServer()
    server.start()